   641→        isError: false,
   642→      }
   643→    }
   644→  },
   645→  [OffersTypes.GET_SUBSCRIBED_OFFER_SUCCESS](
   646→    state: State,
   647→    { data }: { data: { product: productsBenefits, promotions: PromotionUI[], hasKeycloak: boolean } }
   648→  ): State {
   649→    return {
   650→      ...state,
   651→      getSubscribedOffer: {
   652→        data,
   653→        isLoading: false,
   654→        isError: false,
   655→      }
   656→    };
   657→  },
   658→  [OffersTypes.GET_SUBSCRIBED_OFFER_ERROR](state: State) {
   659→    return {
   660→      ...state,
   661→      getSubscribedOffer: {
   662→        data: undefined,
   663→        isLoading: false,
   664→        isError: true,
   665→      }
   666→    };
   667→  },
   668→});
