    41→    if (idHideOnboarding?.text === 'TRUE') continue;
    42→
    43→    const title = idTitle?.text;
    44→    const icon = idIcone?.text as BenefitListLargeItem['icon'];
    45→    const type = idType?.text;
    46→    const text = idText?.text;
    47→    const fullTitle = idFullTitle?.text;
    48→    const fullText = idFullText?.text;
    49→    const description = idText?.text;
    50→    const priority = Number(idPriority?.text ?? 99999);
    51→    const iconColor = ICON_COLOR;
    52→
    53→    if (!(fullText && title && text && fullTitle && icon && type && icon)) {
    54→      console.warn(`Invalid benefit found: ${benefit.idFullTitle?.text}`);
    55→      continue;
    56→    }
    57→
    58→    parsedList.push({
    59→      title,
    60→      icon,
    61→      description,
    62→      onPress: () => onPress?.(benefit, key), // ✅ AQUI
    63→      iconColor,
    64→      priority,
    65→      showIconRight: true,
    66→      rightIconColor: undefined,
    67→    });
    68→  }
    69→
    70→  return parsedList.sort((a, b) => a.priority - b.priority);
    71→}

