     1→import React from 'react';
     2→import styled from 'styled-components/native';
     3→import { Icon } from '@semparar/design-system-app';
     4→
     5→const RENDER_CONFIG = {
     6→  '•': {
     7→    element: 'BULLET',
     8→  },
     9→  '✅': {
    10→    element: 'CHECKED',
    11→  },
    12→} as const;
    13→
    14→type RENDER_CONFIG = typeof RENDER_CONFIG;
    15→type RULE = keyof RENDER_CONFIG;
    16→
    17→const ListItem = styled.View`
    18→  flex-direction: row;
    19→  align-items: flex-start;
    20→  margin-bottom: 8px;
    21→`;
    22→
    23→const MarkerContainer = styled.View`
    24→  width: 20px;
    25→  height: 20px;
    26→  margin-right: 5px;
    27→  align-items: center;
    28→  justify-content: flex-start;
    29→`;
    30→
    31→const ContentText = styled.View`
    32→  flex: 1;
    33→`;
    34→
    35→export type BlockRendererProps = {
    36→  text: string | null | undefined;
    37→  renderText: (text: string) => React.ReactNode;
    38→};
    39→
    40→// Fix the Text component to allow texts starting with '*',
    41→const REGEX_FIX_SINGLE_ASTERIX = /(?<!\*)\*(?!\*)/g;
    42→const MARKERS = Object.keys(RENDER_CONFIG);
    43→const _REGEX = MARKERS.map(marker => `\\${marker}`).join('|');
    44→const REGEX = new RegExp(`(${_REGEX})`, 'g');
    45→
    46→function NodeRenderer(props: {
    47→  rule: RULE;
    48→  text: string;
    49→  renderText: (text: string) => React.ReactNode;
    50→}) {
    51→  const { rule, text, renderText } = props;
    52→
    53→  return (
    54→    <React.Fragment>
    55→      {(() => {
    56→        if (!text) return null;
    57→        const element = RENDER_CONFIG[rule]?.element;
    58→
    59→        switch (element) {
    60→          case 'BULLET': {
    61→            return (
    62→              <ListItem>
    63→                <MarkerContainer>{renderText('▪︎')}</MarkerContainer>
    64→                <ContentText>{renderText(text)}</ContentText>
    65→              </ListItem>
    66→            );
    67→          }
    68→          case 'CHECKED': {
    69→            return (
    70→              <ListItem>
    71→                <MarkerContainer>
    72→                  <Icon
    73→                    name={'icon-check'}
    74→                    size={'xs'}
    75→                    color={'PLUS_COLOR_02'}
    76→                  />
    77→                </MarkerContainer>
    78→                <ContentText>{renderText(text)}</ContentText>
    79→              </ListItem>
    80→            );
    81→          }
    82→        }
    83→      })()}
    84→    </React.Fragment>
    85→  );
    86→}
    87→
    88→export function BlockRenderer(props: BlockRendererProps) {
    89→  const { text: inputText, renderText } = props;
    90→  if (!inputText) return null;
    91→
    92→  const parts = inputText
    93→    .replace(REGEX_FIX_SINGLE_ASTERIX, '✴︎')
    94→    .trim()
    95→    .split(REGEX);
    96→
    97→  if (parts.length < 2) return renderText(inputText);
    98→
    99→  const nodes: React.ReactNode[] = [];
   100→  let pendingMarker: keyof RENDER_CONFIG | null = null;
   101→
   102→  for (let i = 0; i < parts.length; i++) {
   103→    const part = parts[i] as keyof RENDER_CONFIG;
   104→    const rule = RENDER_CONFIG[part];
   105→    const key = `${part.slice(-5)}${i}`;
   106→
   107→    if (rule) {
   108→      if (pendingMarker) {
   109→        nodes.push(
   110→          <NodeRenderer
   111→            key={key}
   112→            renderText={renderText}
   113→            rule={pendingMarker}
   114→            text={''}
   115→          />,
   116→        );
   117→      }
   118→      pendingMarker = part;
   119→    } else if (pendingMarker) {
   120→      const [content, ...rest] = part.trim().split('\n');
   121→
   122→      if (content) {
   123→        nodes.push(
   124→          <NodeRenderer
   125→            key={`${key}`}
   126→            renderText={renderText}
   127→            rule={pendingMarker}
   128→            text={content}
   129→          />,
   130→        );
   131→        for (let text of rest) {
   132→          nodes.push(
   133→            <React.Fragment key={key + text}>
   134→              {renderText(text)}
   135→            </React.Fragment>,
   136→          );
   137→        }
   138→      }
   139→      pendingMarker = null;
   140→    } else if (part) {
   141→      nodes.push(<React.Fragment key={key}>{renderText(part)}</React.Fragment>);
   142→    }
   143→  }
   144→
   145→  if (pendingMarker) {
   146→    nodes.push(
   147→      <NodeRenderer
   148→        key={`last${pendingMarker}`}
   149→        renderText={renderText}
   150→        rule={pendingMarker}
   151→        text={''}
   152→      />,
   153→    );
   154→  }
   155→
   156→  return nodes;
   157→}
