     1→import React, { useMemo, useRef, useState } from "react";
     2→import { Platform, useWindowDimensions } from "react-native";
     3→import normalize from "react-native-normalize";
     4→import { IHandles } from "react-native-modalize/lib/options";
     5→import SelectedPlanDetailsView from "./view";
     6→import { SelectedPlanDetailsProps } from "./Models";
     7→import { connect } from "react-redux";
     8→import { bindActionCreators, Dispatch } from "redux";
     9→import { AppReducers } from "../../redux/reducers/Models";
    10→import { Benefit, offersActions } from "../../redux/ducks/offers";
    11→import { hasSpecialCharacters } from "../../utils/formaters";
    12→import Layout from "../../constants/Layout";
    13→
    14→type BenefitWithWidth = {
    15→    width: number;
    16→    benefit: Benefit;
    17→};
    18→
    19→const SelectedPlanDetails = ({
    20→    navigation,
    21→    offersReducer,
    22→    productsReducer
    23→}: SelectedPlanDetailsProps) => {
    24→
    25→    const modalizeRef = useRef<IHandles>();
    26→
    27→    const { width: SCREEN_WIDTH } = useWindowDimensions();
    28→
    29→    const VERTICAL_MARGIN = normalize(20);
    30→
    31→    const CARD_OFFER_WIDTH = SCREEN_WIDTH - VERTICAL_MARGIN * 2;
    32→
    33→    const availableLimit = productsReducer.data[0].Limite
    34→
    35→    const [benefitDetailData, setBenefitDetailData] = useState<Benefit>();
    36→
    37→    const benefits = offersReducer.getSubscribedOffer.data?.product?.benefits ?? {}
    38→    const benefitValues = Object.values(benefits).filter(
    39→        (b): b is Benefit => !!b?.idResume?.text
    40→    );
    41→    const product = { ...offersReducer.getSubscribedOffer.data?.product, benefitTags: benefitValues }
    42→
    43→    const handleNavigationGoBack = () => {
    44→        navigation.goBack()
    45→    }
    46→
    47→    const handleItemOnPress = (value: Benefit) => {
    48→        if (modalizeRef?.current?.open) {
    49→            modalizeRef?.current?.open();
    50→        }
    51→        if (value.hasOwnProperty('idText')) {
    52→            setBenefitDetailData(value);
    53→        }
    54→    };
    55→
    56→    const promotionObj = offersReducer?.getSubscribedOffer.data?.promotions;
    57→    const hasPromotion = !!promotionObj && promotionObj?.length > 0
    58→
    59→    const promotionRange = hasPromotion ? promotionObj[0].range : ''
    60→    const promoDiscountedValue =
    61→        hasPromotion
    62→            ? String(Number(product?.mensalidade) * Number(promotionObj[0].discount))
    63→            : '0'
    64→
    65→    const stringWidth = (text: string, fontSize = 10, charSpacingRatio = 0.5): number => {
    66→        const isAndroid = Platform.OS === 'android'
    67→        const isSmallDevice = Layout.isSmallDevice
    68→
    69→        const baseWidth = text.length * fontSize * charSpacingRatio
    70→
    71→        const specialAdjustment = hasSpecialCharacters(text) ? VERTICAL_MARGIN / 2 : 0;
    72→
    73→        const buffer = isAndroid
    74→            ? (isSmallDevice ? VERTICAL_MARGIN / 6 : 0) - (VERTICAL_MARGIN / 2)
    75→            : (isSmallDevice ? VERTICAL_MARGIN * 2 : VERTICAL_MARGIN);
    76→
    77→
    78→        return Math.ceil(baseWidth + buffer + specialAdjustment + 20);
    79→    }
    80→
    81→    const reorderBenefitsLayout = (benefits: Benefit[]) => {
    82→        const lines: BenefitWithWidth[][] = [];
    83→
    84→        const benefitsWithWidth = benefits.filter((benefit) => benefit).
    85→            map((benefit) => ({
    86→                width: stringWidth(benefit?.idResume?.text ?? ""),
    87→                benefit: benefit,
    88→            }));
    89→
    90→        benefitsWithWidth.forEach(benefit => {
    91→            let bestLineIdx = -1;
    92→            let bestRemainingSpace = Infinity;
    93→
    94→            for (let idx = 0; idx < lines.length; idx++) {
    95→                const line = lines[idx];
    96→                const usedWidth = line.reduce((sum, b) => sum + b.width, 0);
    97→                const remainingSpace = CARD_OFFER_WIDTH - usedWidth;
    98→
    99→                if (benefit.width <= remainingSpace && remainingSpace - benefit.width < bestRemainingSpace) {
   100→                    bestRemainingSpace = remainingSpace - benefit.width;
   101→                    bestLineIdx = idx;
   102→                    break;
   103→                }
   104→            }
   105→
   106→            if (bestLineIdx >= 0) {
   107→                lines[bestLineIdx].push(benefit);
   108→            } else {
   109→                lines.push([benefit]);
   110→            }
   111→        })
   112→
   113→        return lines.flatMap(line => line.map(({ benefit }) => benefit));
   114→    }
   115→
   116→    const reorderedBenefitTags = useMemo(() => {
   117→        if (!product?.benefitTags) return [];
   118→        return reorderBenefitsLayout(product?.benefitTags);
   119→    }, [product?.benefitTags, CARD_OFFER_WIDTH]);
   120→
   121→
   122→
   123→    return (
   124→        <SelectedPlanDetailsView
   125→            handleNavigationGoBack={handleNavigationGoBack}
   126→            product={product}
   127→            cardOfferWidth={CARD_OFFER_WIDTH}
   128→            availableLimit={availableLimit}
   129→            benefits={benefitValues}
   130→            benefitDetailData={benefitDetailData}
   131→            handleItemOnPress={handleItemOnPress}
   132→            modalizeRef={modalizeRef}
   133→            setBenefitDetailData={setBenefitDetailData}
   134→            isPromotion={hasPromotion}
   135→            promotionRange={promotionRange}
   136→            promoDiscountedValue={promoDiscountedValue}
   137→            reorderedBenefitTags={reorderedBenefitTags}
   138→        />
   139→    );
   140→}
   141→
   142→export const mapStateToProps = ({
   143→    customerReducer,
   144→    offersReducer,
   145→    productsReducer
   146→
   147→}: AppReducers) => ({
   148→    customerReducer,
   149→    offersReducer,
   150→    productsReducer
   151→});
   152→
   153→export const mapDispatchToProps = (dispatch: Dispatch) => {
   154→    return bindActionCreators(
   155→        {
   156→            ...offersActions
   157→        },
   158→        dispatch,
   159→    );
   160→};
   161→
   162→export default connect(mapStateToProps, mapDispatchToProps)(SelectedPlanDetails);
