    43→export const formatToCurrency = (
    44→  fullValue: number | undefined | string,
    45→): string => {
    46→  if (typeof fullValue === 'undefined') return `R$ 0,00`;
    47→
    48→  const [value, cents] = String(fullValue).replace('-', '').split('.');
    49→
    50→  const formattedCents = cents ? cents.padEnd(2, '0') : '00';
    51→  let formattedValue = '';
    52→
    53→  for (let i = 0; i < value.length; i += 1) {
    54→    const currentDigit = value[value.length - 1 - i];
    55→
    56→    if (i > 0 && i % 3 === 0) {
    57→      formattedValue = `${currentDigit}.${formattedValue}`;
    58→    } else {
    59→      formattedValue = `${currentDigit}${formattedValue}`;
    60→    }
    61→  }
    62→
    63→  return `R$ ${Number(fullValue) >= 0 ? '' : '-'}${formattedValue},${formattedCents[0]
    64→    }${formattedCents[1]}`;
    65→};
