    88→                0;
    89→              const conversionFactor = (() => {
    90→                if (typeof rawCF === 'number') return rawCF;
    91→                if (typeof rawCF === 'string') {
    92→                  const n = Number(
    93→                    String(rawCF)
    94→                      .replace(',', '.')
    95→                      .replace(/[^0-9.-]/g, ''),
    96→                  );
    97→                  return Number.isFinite(n) ? n : 0;
    98→                }
    99→                return 0;
   100→              })();
   101→              const productCode =
   102→                (product as any).productCode ?? (product as any).code;
   103→              const campaingId =
   104→                (product as any).campaingId ??
   105→                (product as any).campaignId ??
   106→                undefined;
   107→
   108→              const hasRedeemed = await checkHasRedeemed();
   109→              if (hasRedeemed) {
   110→                navigation.navigate('InvoiceCashbackPoints', {
   111→                  conversionFactor,
   112→                  productCode,
   113→                  campaingId,
   114→                });
   115→              } else {
   116→                navigation.navigate('InvoiceCashbackOnboarding', {
   117→                  conversionFactor,
   118→                  productCode,
   119→                  campaingId,
   120→                });
   121→              }
   122→            }
   123→          : handleOnPress(normalizedName);
   124→
   125→        return builder
   126→          .reset()
   127→          .setId(index + 1)
   128→          .setText(product.name)
   129→          .setIcon(icon)
   130→          .setOnPress(onPress)
   131→          .build();
   132→      });
   133→    },
   134→    [
   135→      handleOnPress,
   136→      checkHasRedeemed,
   137→      navigation,
   138→    ],
   139→  );
   140→
   141→  return buildPointsCardItems;
   142→};
