### Fase 2: Component Registry (1 semana)

Em vez de switch/case espalhados, criar um **registro de componentes**:

```typescript
// components/BenefitRenderers/registry.ts
const BENEFIT_RENDERERS: Record<string, React.ComponentType<BenefitProps>> = {
  'card': DefaultBenefitCard,
  'card_variant': VariantBenefitCard,
  'insurance': InsuranceBenefitCard,
  'phone_action': PhoneActionBenefit,    // Usa idPhoneIcon, idPhoneTitle, etc
  'online_action': OnlineActionBenefit,  // Usa idOnlineIcon, idOnlineTitle, etc
  'link_only': LinkOnlyBenefit,
};

// Uso:
function BenefitRenderer({ benefit }: { benefit: Benefit }) {
  const type = benefit.idType?.text || 'card';
  const Component = BENEFIT_RENDERERS[type] || DefaultBenefitCard;
  return <Component benefit={benefit} />;
}
```

**Resultado**: Backend pode enviar `idType: "phone_action"` e o componente correto é renderizado. Sem deploy, só cadastrar o tipo no backend.

---

### Fase 3: Layout Dinâmico Simples (1-2 semanas)

Para telas como voucher, definir schema de componentes:

```typescript
// types/ScreenSchema.ts
type ScreenComponent = 
  | { type: 'header'; title: RichText }
  | { type: 'points_display'; binding: string }
  | { type: 'input'; id: string; label: string; inputType: 'points' | 'currency' }
  | { type: 'rich_text'; content: RichText }
  | { type: 'button'; text: string; action: Action }
  | { type: 'link'; text: string; action: Action }
  | { type: 'alert'; style: 'info' | 'warning' | 'error'; content: RichText }
  | { type: 'spacer'; size: 'sm' | 'md' | 'lg' }
  | { type: 'divider' };

type RichText = Array<
  | { text: string }
  | { text: string; bold: true }
  | { text: string; link: string }
>;

type Action = 
  | { type: 'navigate'; uri: string }
  | { type: 'api_call'; endpoint: string; method: string }
  | { type: 'set_value'; target: string; value: any };

// Schema da tela vem do backend
interface ScreenSchema {
  id: string;
  header?: { title: string; showBack?: boolean };
  body: ScreenComponent[];
  footer?: ScreenComponent;
}
```

**Renderer simples**:

```typescript
// components/DynamicScreen/index.tsx
function DynamicScreen({ schema }: { schema: ScreenSchema }) {
  return (
    <Screen header={schema.header}>
      <ScrollView>
        {schema.body.map((component, i) => (
          <ComponentRenderer key={i} component={component} />
        ))}
      </ScrollView>
      {schema.footer && <ComponentRenderer component={schema.footer} />}
    </Screen>
  );
}

function ComponentRenderer({ component }: { component: ScreenComponent }) {
  switch (component.type) {
    case 'rich_text':
      return <RichTextRenderer content={component.content} />;
    case 'button':
      return <Button text={component.text} onPress={() => handleAction(component.action)} />;
    case 'input':
      return <InputBox id={component.id} label={component.label} />;
    // ... etc
  }
}
```

