      type: 'default',
      icon: 'icon-clock',
      description: 'O cashback acontece em até 72h',  // HARDCODED
    },
  ];
};
```

### 1.5 Filtros Hardcoded

**ExtractRewardProgram/index.ts:**
```typescript
const getFilterGroups: FilterGroup[] = useMemo(() => {
  return [
    {
      label: 'Períodos',
      options: [
        { label: '7 dias', value: 0 },
        { label: '15 dias', value: 1 },
        { label: '30 dias', value: 2 },
        { label: '60 dias', value: 3 },
